using System;

namespace Usuario.Domain.Entities
{
    public class User
    {
        public Guid Id { get; private set; }
        public string Name { get; private set; }
        public string CPF { get; private set; }
        public DateTime DateOfBirth { get; private set; }
        public string Profession { get; private set; }
        public string Email { get; private set; }

        private User() { }

        public User(Guid id, string name, string cpf, DateTime dateOfBirth, string profession, string email)
        {
            Id = id;
            Name = name;
            CPF = cpf;
            DateOfBirth = dateOfBirth;
            Profession = profession;
            Email = email;
        }

        public void Update(string name, string profession, string email)
        {
            Name = name;
            Profession = profession;
            Email = email;
        }
    }
}

using System.Text.RegularExpressions;

namespace Usuario.Domain.ValueObjects
{
    public class CPF
    {
        public string Value { get; private set; }

        private CPF() { }

        public CPF(string value)
        {
            if (!IsValid(value))
                throw new ArgumentException("Invalid CPF");

            Value = value;
        }

        public static bool IsValid(string cpf)
        {
            if (string.IsNullOrWhiteSpace(cpf)) return false;

            cpf = Regex.Replace(cpf, "[^0-9]", "");

            if (cpf.Length != 11) return false;

            var sameDigits = new Regex(@"^(\d)\1+$");
            if (sameDigits.IsMatch(cpf)) return false;

            var numbers = cpf.Select(c => int.Parse(c.ToString())).ToArray();
            var sum = 0;

            for (int i = 0; i < 9; i++)
                sum += numbers[i] * (10 - i);

            var remainder = sum % 11;
            var firstDigit = remainder < 2 ? 0 : 11 - remainder;

            if (numbers[9] != firstDigit) return false;

            sum = 0;
            for (int i = 0; i < 10; i++)
                sum += numbers[i] * (11 - i);

            remainder = sum % 11;
            var secondDigit = remainder < 2 ? 0 : 11 - remainder;

            return numbers[10] == secondDigit;
        }
    }
}

using MediatR;
using Usuario.Application.Common;

namespace Usuario.Application.Users.Commands.CreateUser
{
    public record CreateUserCommand(string Name, string CPF, DateTime DateOfBirth, string Profession, string Email) : IRequest<Result<Guid>>;
}

using System;
using System.Threading;
using System.Threading.Tasks;
using MediatR;
using Usuario.Application.Common;
using Usuario.Domain.Entities;
using Usuario.Domain.Interfaces;

namespace Usuario.Application.Users.Commands.CreateUser
{
    public class CreateUserCommandHandler : IRequestHandler<CreateUserCommand, Result<Guid>>
    {
        private readonly IUserRepository _userRepository;

        public CreateUserCommandHandler(IUserRepository userRepository)
        {
            _userRepository = userRepository;
        }

        public async Task<Result<Guid>> Handle(CreateUserCommand request, CancellationToken cancellationToken)
        {
            var user = new User(Guid.NewGuid(), request.Name, request.CPF, request.DateOfBirth, request.Profession, request.Email);

            await _userRepository.AddAsync(user);

            return Result<Guid>.Success(user.Id);
        }
    }
}

namespace Usuario.Application.Common
{
    public class Result<T>
    {
        public bool IsSuccess { get; }
        public T Value { get; }
        public string Error { get; }

        private Result(bool isSuccess, T value, string error)
        {
            IsSuccess = isSuccess;
            Value = value;
            Error = error;
        }

        public static Result<T> Success(T value) => new Result<T>(true, value, null);

        public static Result<T> Failure(string error) => new Result<T>(false, default, error);
    }
}

using System;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
using Usuario.Domain.Entities;
using Usuario.Domain.Interfaces;

namespace Usuario.Infrastructure.Persistence
{
    public class UserRepository : IUserRepository
    {
        private readonly UserDbContext _context;

        public UserRepository(UserDbContext context)
        {
            _context = context;
        }

        public async Task AddAsync(User user)
        {
            await _context.Users.AddAsync(user);
            await _context.SaveChangesAsync();
        }
    }
}

using Microsoft.EntityFrameworkCore;
using Usuario.Domain.Entities;

namespace Usuario.Infrastructure.Persistence
{
    public class UserDbContext : DbContext
    {
        public DbSet<User> Users { get; set; }

        public UserDbContext(DbContextOptions<UserDbContext> options) : base(options) { }

        protected override void OnModelCreating(ModelBuilder modelBuilder)
        {
            modelBuilder.Entity<User>(entity =>
            {
                entity.HasKey(e => e.Id);
                entity.Property(e => e.Name).IsRequired().HasMaxLength(100);
                entity.Property(e => e.CPF).IsRequired().HasMaxLength(11);
                entity.Property(e => e.DateOfBirth).IsRequired();
                entity.Property(e => e.Profession).HasMaxLength(100);
                entity.Property(e => e.Email).IsRequired().HasMaxLength(100);
            });
        }
    }
}

using System;
using System.Threading.Tasks;
using MediatR;
using Microsoft.AspNetCore.Mvc;
using Usuario.Application.Users.Commands.CreateUser;

namespace Usuario.API.Controllers
{
    [ApiController]
    [Route("api/users")]
    public class UserController : ControllerBase
    {
        private readonly IMediator _mediator;

        public UserController(IMediator mediator)
        {
            _mediator = mediator;
        }

        [HttpPost]
        public async Task<IActionResult> CreateUser([FromBody] CreateUserCommand command)
        {
            var result = await _mediator.Send(command);

            if (!result.IsSuccess)
                return BadRequest(result.Error);

            return CreatedAtAction(nameof(GetUserById), new { id = result.Value }, null);
        }

        [HttpGet("{id:guid}")]
        public IActionResult GetUserById(Guid id)
        {
            // Placeholder for GetUserById implementation
            return Ok();
        }
    }
}
